import json
import re

# Load the data from the previous query
with open('var_functions.query_db:12.json', 'r') as f:
    releases = json.load(f)

# Filter and parse the version info
package_versions = []
for pkg in releases:
    try:
        version_info = json.loads(pkg['VersionInfo'])
        if version_info.get('IsRelease'):
            package_versions.append({
                'Name': pkg['Name'],
                'Version': pkg['Version'],
                'Ordinal': version_info.get('Ordinal', 0)
            })
    except:
        pass

# Group by package name and find the latest version
from collections import defaultdict
latest_packages = {}
for pkg in package_versions:
    name = pkg['Name']
    if name not in latest_packages or pkg['Ordinal'] > latest_packages[name]['Ordinal']:
        latest_packages[name] = pkg

latest_versions_list = [{'Name': k, 'Version': v['Version'], 'Ordinal': v['Ordinal']} 
                        for k, v in latest_packages.items()]

print('__RESULT__:')
print(json.dumps(latest_versions_list[:10]))

